const BRIDGE_ARGS = ["\/Users\/youkipepper\/.ping-island\/bin\/ping-island-bridge","--source","claude","--client-kind","opencode","--client-name","OpenCode","--client-origin","cli","--client-originator","OpenCode","--thread-source","opencode-plugin"];
